var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"으음…","JPN":"うーん……","ENG":"Mm…","TWN":"嗯…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"침대에서 깨어나는 게 아주 일상이네.","JPN":"いつの間にか気を失い、気づいたらベッドの上……もう日常になってしまったな。","ENG":"Waking up in a bed again. Seems like a habit.","TWN":"在床上醒來已經是家常便飯呢。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"내 다리에 감각이 없어.","JPN":"足に感覚がない。","ENG":"I can't feel my legs.","TWN":"腳沒有知覺。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"나무에 빨래처럼 걸려서 기절해있었으니까.","JPN":"気絶している間、木の枝に洗濯物のように引っかかっていたからな。","ENG":"You were hanging from a tree like laundry while you passed out.","TWN":"因為你暈倒的時候，像洗好的衣服一樣掛在樹上。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"우리가 도시로 간 사이, 예정 주기에 없던 먹비가 쏟아졌더군.","JPN":"私たちが都市に出ている間、予定周期にはなかった墨雨が降ったようだ。","ENG":"While we were in the city, an unscheduled wave of Ink Rain hit.","TWN":"我們去城市的這段時間，下了一場不在預期週期裡的墨雨。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"침식현상의 주기는 절대적이지 않으니까. 어디까지나 참고용일 뿐이지.","JPN":"侵食現象の周期は絶対的ではない。あくまで参考にしているだけだ。","ENG":"The Counterside Effect cycle isn't absolute. It's only a reference point.","TWN":"侵蝕現象的週期不是絕對的，只是參考值而已。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"앤디 말로는 장치가 가동된 흔적이 있다고 했어.","JPN":"アンディーの話によると、装置が稼働した痕跡があったそうだが。","ENG":"Andy said she found signs that the device had been activated.","TWN":"安狄說裝置有運作過的痕跡。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"얼마나 위험한 지도 모르면서 혼자 뛰어든 거야?","JPN":"どれほど危険かも知らないくせに、一人で飛び込んだのか？","ENG":"Did you jump in without knowing how dangerous it was?","TWN":"你連那有多危險都不知道，就一個人衝進去了嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"<color=#ffd34c>과.위.힘</color>은 비축할 방도가 없는 휘발성 에너지니까.","JPN":"<color=#ffd34c>過向力</color>は備蓄する術がない、揮発性のエネルギーゆえ。","ENG":"<color=#ffd34c>PTP</color> is a volatile energy. There's no way to store it.","TWN":"<color=#ffd34c>回力量</color>是一種沒有儲存方法的揮發性能量。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이번 기회를 놓치면 언제 또 작동할지 모르잖나.","JPN":"この機会を逃せば、次はいつ稼働できるか分からないではないか。","ENG":"If I missed this opportunity, I wouldn't know when it might run again.","TWN":"要是錯過這次機會，不知道什麼時候才會再運作。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"과거는 다녀왔나? 이번엔 거기서 뭘 보고 누굴 만났지?","JPN":"それで、過去には行ってきたのか？　今回はそこで何を見、誰に会った？","ENG":"So? Did you go back to the past? What did you see, and who did you meet this time?","TWN":"你回到過去了嗎？這次在那裡看到什麼？見到了誰？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"다 설명하려면 얘기가 좀 길어질 텐데. 괜찮겠나?","JPN":"すべて説明すると長くなるが、よいのか？","ENG":"It'll be a long story if I explain everything. Is that all right?","TWN":"說來話長，你有時間嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"걱정 마. 땅콩이라면 잔뜩 사왔으니까.","JPN":"心配するな。ピーナッツなら山ほど買ってある。","ENG":"Go ahead. I brought plenty of peanuts.","TWN":"放心，我買了很多花生。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부는 그 연화 언니를 다시 만난 거구나.","JPN":"じゃあ、そのレンカってお姉さんにまた会えたんだね。","ENG":"So you saw that Yeonhwa lady again, huh?","TWN":"你又見到那個蓮華姊姊啦。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그럼 이번에도 그 언니한테 당하고 돌아온 거야?","JPN":"それで、今回もそのお姉さんにやられて帰らされたの？","ENG":"Did she beat you up again this time?","TWN":"所以這次也是被那個姊姊打敗後回到現實嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"적어도 이번엔 기습이 아닌 정당한 대결이었지.","JPN":"少なくとも今回は不意打ちではない正面からの勝負であった。","ENG":"At least this time it was a duel, not an ambush.","TWN":"至少這次不是偷襲，是正面對決。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"너를 돕겠다고 하니, 내 실력을 증명하라며 칼을 뽑더군.","JPN":"彼女を助けると言うと、某の腕を証明してみろと剣を抜いてきてな。","ENG":"I told her I came to help, and she drew her sword to see if I had what it takes.","TWN":"我說要幫助她，她就拔出劍，要我證明我的實力。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그래서 졌나?","JPN":"それで負けたのか？","ENG":"So you lost?","TWN":"然後你打輸了？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나름대로 준비된 줄 알았지만, 얼마 버티지 못했네.","JPN":"自分なりに十分鍛えていると思っていたが、そう長くは持たなかった。","ENG":"I thought I trained enough, but I couldn't hold out for long.","TWN":"我以為我已經受過很多訓練，但還是一下就敗陣。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그리고 보다시피, 이렇게 강제로 돌아오게 됐지.","JPN":"そして見ての通り、帰って来たというわけだ。","ENG":"And as you can see, here I am again.","TWN":"接著就像你們看到的一樣，我回到這裡。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그 언니도 좀 이해가 안 되네. 도와주러 왔다는 사람을 그런 식으로 밀어내다니.","JPN":"そのお姉さんも変わってるね。助けに来たって人をそんな風に拒むだなんて。","ENG":"I don't get her. Why push away someone who came to help?","TWN":"那個姊姊也真奇怪，為何要推開一個想要來幫忙的人？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부의 동료라면서, 왜 계속 그러는 걸까?","JPN":"師匠の仲間なのに、毎回なんでだろう？","ENG":"She's your old comrade, isn't she? Why is she still like that?","TWN":"她不是師父的夥伴嗎？為什麼要推開夥伴？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"실전에서 어설픈 도움은 발목만 잡을 뿐이란 거겠지.","JPN":"実践では下手な助太刀など、足手まといにしかならんということだろう。","ENG":"Maybe because sloppy help in the field can be more of a hindrance.","TWN":"大概是覺得在實戰中，三腳貓的功夫只會幫倒忙吧。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"서생을 압도할 정도의 실력자도 살아남지 못할 작전이라면, 충분히 합리적인 판단이야.","JPN":"ショウを圧倒するほどの実力者が生き残れなかったわけだし、合理的な判断だな。","ENG":"If someone strong enough to overwhelm Seosaeng still didn't survive, then her judgment isn't wrong.","TWN":"要是她的能力好到可以打倒書生，但卻連她都沒能活下來，那她的判斷完全是合理的。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"부정은 못하겠군. 내가 그녀보다 강했다면 결과는 달랐을 테니.","JPN":"否定できんな。某が彼女より強かったなら、結果は違ったであろう。","ENG":"I won't argue. If I were stronger than her, it might have turned out differently.","TWN":"我無法反駁。如果我比她強，結果肯定會不同。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신에게 그 연화라는 사람은 과거로 가서 도와야 할 만큼 중요한 사람인가?","JPN":"お前にとってそのレンカって人は、過去に戻って助けないといけないほど大事な人間なのか？","ENG":"Is she really someone you'd go back in time to save?","TWN":"對你來說，那個叫蓮華的人是重要到必須回到過去去幫助她的人嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"연화는 나와 생사고락을 함께하던 동료… 어쩌면 그 이상의 존재일세.","JPN":"レンカは某と苦楽を共にした仲間……もしかすると、それ以上の存在だ。","ENG":"Yeonhwa was a comrade through life and death… maybe more than that.","TWN":"蓮華是與我一同經歷生死、同甘共苦的夥伴…或許是超越夥伴的存在。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"기억을 지운 뒤에도 꿈에서 나타났다는 건, 분명 그만큼 중요하다는 의미겠지.","JPN":"記憶を消した後も夢に現れ続けていたということは、それほど大事だという意味だろう。","ENG":"If she kept appearing in my dreams even after I erased my memories, it must mean she mattered that much.","TWN":"在我消除記憶後，她還是會在夢中出現，這就表示她很重要吧。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"꿈에 나타난 여자가 자길 찾아 달라고 한 게 이 모든 일을 벌인 계기라니…","JPN":"今やっている事の発端が、夢に現れた女に自分を助けてほしいと言われたから……だったとは。","ENG":"So you're saying all of this started because some woman in a dream asked you to find her…","TWN":"夢裡出現的女人要他去找自己，這就是引發所有事情的契機…"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"천재과학자의 입에서 나왔다곤 믿기 힘들군.","JPN":"天才科学者の口から出てきた話だとは信じがたい。","ENG":"Hard to believe that came from the mouth of a genius scientist.","TWN":"這話從一個天才科學家嘴裡說出來，真讓人難以置信。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"}}}},{"id":"L50_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"때로는 과학적으로 설명할 수 없는 일도 있는 거라고 생각해.","JPN":"時には、科学的に説明できないこともあるってことだよ。","ENG":"I think some things just can't be explained with science.","TWN":"我想，有時候也會發生一些無法用科學解釋的事情。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그 꿈 속의 사람이 진짜라는 걸 두 번이나 확인했잖아? 연화라는 이름도 알아냈고.","JPN":"あの夢の中の人は本物だって、2回も確認できたんだよ？　レンカという名前も分かったし。","ENG":"And you've confirmed twice now that she's real. You even learned her name.","TWN":"都確認過二次了，夢裡那個人是真的，還知道她叫蓮華。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"과학자라고 해서 꼭 논리적인 말만 하는 게 아니란 건 알겠네.","JPN":"科学者だからと言って、必ずしも論理的な話をするわけではない、ということは分かった。","ENG":"I guess even scientists don't always talk logically.","TWN":"我總算明白了，科學家也並非總是只說合乎邏輯的話。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그래서 이제 어쩔 셈이지? 또 과거로 돌아가서 그 여자와 겨뤄볼 셈인가?","JPN":"それで、これからどうするつもりだ？　また過去に戻ってその女と勝負するのか？","ENG":"So what's next? Planning to go back and duel her again?","TWN":"所以你現在打算怎麼辦？再回到過去，和那個女人較量一番嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그녀를 이겨서 설득하는 게 쉽지는 않겠지.","JPN":"彼女を打ち負かして説得することは難しいだろう。","ENG":"Convincing her by winning won't be easy.","TWN":"要打敗她來説服她，恐怕不容易。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"하지만 잃어버린 기억의 단서를 모을 수 있다면, 그것만으로도 과거에 갈 이유는 충분해.","JPN":"しかし、失った記憶の手がかりを集められるという点だけでも過去に戻る理由としては十分だ。","ENG":"But even collecting clues about my lost memories is reason enough to return.","TWN":"但僅僅是收集失去的記憶線索，就已經構成回到過去的理由。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"혹시 과거의 사부는 만나려고 해봤어?","JPN":"過去の師匠には会おうとしてみた？","ENG":"Have you tried meeting the past version of yourself?","TWN":"你試過和過去的師父見面嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"자기 자신을 싫어하는 사람은 없잖아. 궁금한 걸 물어보면 분명 협조해줄 거라 생각하는데!","JPN":"自分のことが嫌いな人っていないじゃない？　気になることを聞いたら、きっと協力してくれるよ！","ENG":"No one hates themselves, right? If you ask questions, he'd probably cooperate!","TWN":"沒有人會討厭自己。你去問他的話，他一定會告訴你的！"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나도 그리 생각했다네. 기억을 잃기 전의 나와 대화를 나눌 수만 있다면 정보를 얻는 데 큰 도움이 되겠지.","JPN":"同意見だ。記憶を失う前の某と話し合うことができれば、情報集めにかなり役立つだろう。","ENG":"I think so too. Talking to the version of me before the memory loss would be a big help.","TWN":"我也這麼想。如果能和失去記憶前的我對話，對獲取情報會有很大的幫助。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"하지만 <color=#ffd34c>과.위.장</color>은 정해진 장소의 과거 밖에 들출 수 없으니, 간단치 않겠더군.","JPN":"だが、<color=#ffd34c>過向装</color>は決まった場所の過去にしか戻れぬものだし……簡単にはいかんな。","ENG":"But the <color=#ffd34c>DTP</color> can only reach a fixed location in the past. It's not easy.","TWN":"但<color=#ffd34c>回裝置</color>只能回到特定地點，恐怕不容易。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"하긴, 지난 번에도 그 단방향 통신이란 걸로 목소리 밖에 못 들었으니까.","JPN":"そうだね。この前だって、あの一方向通信ってやつのせいで声しか聞けなかったもんね。","ENG":"Right. Last time, all we got was one-way comms.","TWN":"說得也是，上次也只是透過單向通訊聽到聲音而已。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아무래도 만나기 쉽지 않은 장소에 있나 보네.","JPN":"たぶん、なかなか会えない場所にいるんだよ。","ENG":"He's probably somewhere hard to reach.","TWN":"看來他可能是在一個不容易到的地方。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그래도 확실히 알게 된 사실이 있어. 과거의 나 또한 <color=#ffd34c>과.위.장</color>과 비슷한 장치를 만들었단 걸세.","JPN":"それでもはっきりしたことはある。過去の某も、<color=#ffd34c>過向装</color>と似たような装置を作っていたということだ。","ENG":"Still, I did confirm something. The past me built a device similar to the <color=#ffd34c>DTP</color>.","TWN":"不過，我發現一件事。過去的我也有製造和<color=#ffd34c>回裝置</color>類似的東西。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"연화는 그 장치를 이용해 범이라는 괴물을 쫓고 있었지.","JPN":"レンカをその装置を利用して「虎」と呼ばれる化け物を追っていた。","ENG":"Yeonhwa was using that device to chase the Tiger.","TWN":"蓮華就是利用那個裝置來追捕那個叫老虎的怪物。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 여자가 당신이 만든 장치를 쓰고 있었다고?","JPN":"その女が、お前の作った装置を使っていただと？","ENG":"She was using something you built?","TWN":"那個女人在使用你製造的裝置？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 말은 괴물을 잡으려면 과거로 가야 한다는 건가?","JPN":"つまり、化け物を倒すためには過去に行く必要があるということか？","ENG":"So to stop the monster, you have to go back in time?","TWN":"這話的意思是，如果要抓住那個怪物，就必須回到過去嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"오늘날 먹비라 불리는 재앙은 그 범이 흘리는 피 때문이라는 말을 들었어.","JPN":"現在墨雨と呼ばれるあの災害は、その虎が流す血が原因だと言っていた。","ENG":"The disaster we now call Ink Rain is caused by the blood of the Tiger.","TWN":"據說，今日被稱之為墨雨的災難，就是那個老虎流出的血。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"먹비가 품은 힘이 과거로 통하는 길을 열 수 있다면, 그 피의 주인 또한 마찬가지겠지.","JPN":"墨雨が宿す力が過去へ向かう道を開くのであれば、血の主もまたそうであろう。","ENG":"If the power in Ink Rain opens paths to the past, then the owner of that blood might as well.","TWN":"若墨雨蘊含的力量能開啟通往過去的道路，那墨雨的源頭，那隻怪物理應也能辦到。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"타임머신 능력이 탑재된 침식체라… 관리국이 못 잡고 애를 먹었을 만도 하군.","JPN":"タイムマシン能力を搭載した侵食体か……管理局も手こずるわけだ。","ENG":"A C.O. with time travel powers… no wonder the Administration couldn't catch it.","TWN":"一個搭載時光機能力的侵蝕體…難怪管理局會難以應付。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"녀석의 피를 이용해 그런 장치를 다룰 생각을 한 당신도 예사는 아니지만 말이야.","JPN":"やつの血を利用してそんな装置を扱おうと思い立ったお前も大したものだ。","ENG":"And you thought of making a device using its blood? That's not exactly normal either.","TWN":"不過，你竟然能想到利用那傢伙的血來製造裝置，你果然也不是個普通人。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"예전의 사부도 똑같은 장치를 만들었다면… 그 장치는 일종의 출입문일 지도 모르겠네.","JPN":"昔の師匠も同じ装置を作ったってことは……その装置は、いわゆる出入口なのかもしれないね。","ENG":"If past Master made the same device… maybe it's more like a gateway.","TWN":"如果過去的師父也有一樣的裝置…那那個裝置或許是一個出入口。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부가 두 번이나 같은 장소, 같은 과거에서 연화 언닐 만난 건 우연이 아니었을지도 몰라.","JPN":"師匠が2度も同じ場所、同じ過去でレンカさんに会えたのは偶然じゃなかったかもしれない。","ENG":"It's no coincidence you met Yeonhwa twice in the same place and time.","TWN":"師父兩次在同一個地點、同一個過去遇見蓮華姊姊，這不是偶然。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"지금의 사부가 만든 <color=#ffd34c>과.위.장</color>은 과거의 사부가 만든 <color=#ffd34c>과.위.장</color>으로 통하는 통로였던 셈인 거지!","JPN":"今の師匠が作った<color=#ffd34c>過向装</color>は、過去の師匠が作った<color=#ffd34c>過向装</color>に繋がる通路になったの！","ENG":"The <color=#ffd34c>DTP</color> you built was a passage connecting to the one you built in the past!","TWN":"現在的師父製造的<color=#ffd34c>回裝置</color>，是通往過去師父製造的<color=#ffd34c>回裝置</color>的通道！"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"<color=#ffd34c>과.위.장</color>은 반드시 <color=#ffd34c>과.위.장</color>이 있는 곳으로만 통한다는 건가…?","JPN":"<color=#ffd34c>過向装</color>は必ず<color=#ffd34c>過向装</color>がある場所のみへ繋がるということか……？","ENG":"So the <color=#ffd34c>DTP</color> can only reach locations where the <color=#ffd34c>DTP</color> exists…?","TWN":"<color=#ffd34c>回裝置</color>只能通往有<color=#ffd34c>回裝置</color>的地方嗎…？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"아쉽군. 장소를 뜻대로 고를 수만 있다면 훨씬 더 유용한 물건이 됐을 텐데.","JPN":"残念だな。場所を思い通りに決めることができれば、より有用なものになったはずだが。","ENG":"That's a shame. If only we could set the destination freely, it'd be far more useful.","TWN":"真可惜。如果能隨意設定地點的話，那會是個更有用的東西。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"성공은 장담 못하겠지만… 개선하려는 노력은 해볼 걸세.","JPN":"必ず成功するとは言い切れないが……改善するための努力はしてみよう。","ENG":"I can't promise success… but I'll try to improve it.","TWN":"我不敢保證會成功…但我會努力嘗試改良它。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"천하의 서생이 장담 못하는 성공도 있나?","JPN":"天下のショウ様に、成功すると断言できないこともあるのか？","ENG":"Is there really something even Seosaeng can't guarantee?","TWN":"堂堂書生，竟然也有不敢保證的事嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"천하의 내가 여인의 고집 하날 꺾지 못해 두 번이나 칼에 베였다네.","JPN":"天下の某が、女性の意地ひとつに勝てず2度も斬られているのでな。","ENG":"Even someone like me got cut down twice because I couldn't change one woman's mind.","TWN":"這樣的我，因為無法說服一個女人的固執，被她砍了兩次呢。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"몇 번이고 시도를 거듭한다면 언젠간 성공하겠지만, 기회라는 건 성공할 때까지 주어지는 게 아니니까.","JPN":"何度も試せばいずれは成功するだろうが、機会は成功するまで与えられるものではないゆえ。","ENG":"I could try a hundred more times and maybe succeed. But chances don't wait forever.","TWN":"如果反覆嘗試幾次，總有一天會成功，但機會並不會一直給到你成功為止。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그래서? 앞으로 몇 번이나 이런 짓을 더 되풀이할 셈이지?","JPN":"で？　あと何回繰り返すつもりだ？","ENG":"So? How many more times are you planning to try?","TWN":"所以呢？你打算再重複幾次？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"1년 전의 챔버에서… 나를 이해해주던 유일한 동료가 먹비에 잡아 먹혔어.","JPN":"1年前のチェンバーで……某を理解してくれていた唯一の同僚が墨雨に呑まれてな。","ENG":"One year ago in Chamber… the only comrade who understood me was devoured by the Ink Rain.","TWN":"在一年前的強巴…唯一理解我的夥伴遭墨雨吞噬。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그 먹비의 원흉이 내 과거에 있다는 걸 알게 됐을 때, 난 결코 과거의 그림자에서 벗어날 수 없음을 깨달았지.","JPN":"その墨雨の元凶が己の過去にも存在すると分かった時……某は決して過去の影から逃れられないと悟ったのだ。","ENG":"When I learned that the cause of it all lay in my past, I realized I could never escape its shadow.","TWN":"當我知道墨雨的元兇存在於我的過去時，我意識到我永遠無法擺脫過去的陰影。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그리고 머잖아, 먹비보다 더한 참상이 현실에 들이닥칠 걸세.","JPN":"そしてそう遠くない未来に、墨雨を超える惨事が現実を襲うだろう。","ENG":"And soon, something worse than the Ink Rain will arrive.","TWN":"而且很快，比墨雨更慘烈的災難將會降臨現實。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그 참상을 막으려면… 난 과거로 돌아가 연화를 살려야만 해.","JPN":"その惨事を防ぐには……過去に戻ってレンカを助ける必要がある。","ENG":"To stop it… I have to go back to the past and save Yeonhwa.","TWN":"若要阻止那場災難…我必須回到過去拯救蓮華。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"몇 번을 더 되풀이하더라도… 반드시.","JPN":"何度繰り返すことになっても……必ず。","ENG":"No matter… how many times it takes.","TWN":"無論重複多少次…我一定會做到。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부…","JPN":"師匠……","ENG":"Master…","TWN":"師父…"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"과거를 바꾸기 위한 초석이 그 여자와의 결투에서 이기는 거라면…","JPN":"過去を変えるための礎が、その女との勝負に勝つことなら……","ENG":"If the first step to changing the past is winning that duel with her…","TWN":"如果改變過去的基石，是戰勝那個女人…"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"내가 도움을 줄 수도 있어.","JPN":"私が力を貸してやってもいい。","ENG":"Then maybe I can help.","TWN":"我或許能幫上忙。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어르신이 사부를 돕는다고? 어떻게?","JPN":"おばあさんが師匠をどうやって助けるの？","ENG":"You? Help Master? How?","TWN":"阿姨要幫師父？怎麼幫？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"네 사부의 검술은 뛰어나진 않지만, 재능이 없는 건 아니거든.","JPN":"お前の師匠の剣は、技術面は平凡だが、才能がないわけではない。","ENG":"His sword skills aren't great, but he's not untalented.","TWN":"你師父的劍術雖然不出色，但並非沒有天賦。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"가르칠 사람이 있다면 지금보단 훨씬 나아지겠지.","JPN":"教える人がいれば、今よりはたいぶマシになるだろう。","ENG":"With the right instructor, he can do better.","TWN":"有人教的話，會比現在好很多。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"뭐어… 지수 어르신이 잘 싸우는 건 인정하지만, 가르치는 건 좀 다르지 않아?","JPN":"まあ……おばあさんの腕がいいのは認めるけど、教えるとなるとまた別なんじゃないの？","ENG":"I mean… I admit you're strong, granny. But teaching is different, isn't it?","TWN":"嗯…我承認智秀姨很能打，但教別人是另外一回事吧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"누굴 가르쳐본 경험은 없다.","JPN":"誰かを教えた経験はない。","ENG":"I've never taught anyone.","TWN":"我沒有教過任何人的經驗。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그러니 싫다면 강요하진 않겠어.","JPN":"気が乗らないなら、強制はしない。","ENG":"And I won't force you if you don't want it.","TWN":"不需要的話不勉強。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"한 수 가르침을 부탁하지.","JPN":"では頼む。","ENG":"Please instruct me.","TWN":"請賜教。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"다음 먹비가 내릴 때까지 넋 놓고 기다리는 것보단 나을 테니.","JPN":"次の墨雨が降るまで、手放しで待つよりはマシだろう。","ENG":"Better than sitting around waiting for the next Ink Rain to fall.","TWN":"總比毫無作為地等到下一場墨雨降臨要好。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"연락이 되지 않는다고?","JPN":"連絡が取れないだと？","ENG":"No contact?","TWN":"聯絡不上？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L28_1","type":"dialog","speaker":"WATCHER_NPC_NULL_14","text":{"KOREA":"예. 벌써 나흘째 부재입니다.","JPN":"はい、もう4日も不在が続いています。","ENG":"No. It's been four days now.","TWN":"是的，已失聯四天。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATCHER_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"별로 문제 삼을 일은 아니네. 그 검사는 원래 늘 멋대로였잖아?","JPN":"別に問題はない。あの剣士は以前から好き勝手にしていただろう。","ENG":"Doesn't sound like a problem. That woman always did go rogue, right?","TWN":"這不是什麼大問題。那個劍士本來就是任意而為不是嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATCHER_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WATCHER_NPC_NULL_14","text":{"KOREA":"3시간 전, 요원들이 위치를 파악하려 했지만 실패했어요. 추적용 칩을 임의로 파기한 것 같습니다.","JPN":"3時間前、要員たちが居場所を把握しようと試みましたが、失敗しました。追跡用のチップをわざと破棄したようです。","ENG":"Agents tried to track her three hours ago but failed. She seems to have destroyed her tracking chip.","TWN":"三小時前，我們試圖追蹤定位，但嘗試失敗。她似乎擅自破壞了追蹤晶片。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATCHER_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"흐음…","JPN":"ふむ……","ENG":"Hmm…","TWN":"嗯…"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATCHER_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"그 검사의 심경에 어떤 변화라도 생긴 걸까?","JPN":"あの剣士の心境に何か変化でも生じたのだろうか。","ENG":"Has something changed her mind?","TWN":"那個劍士的想法有發生什麼變化嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATCHER_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"WATCHER_NPC_NULL_14","text":{"KOREA":"어쩌면 처음부터 저희의 정보력을 이용할 생각뿐이었을 지도 모르죠.","JPN":"もしかすると、最初から私たちの情報力を利用するつもりだけだったのかもしれません。","ENG":"Maybe she only ever intended to use our intel in the first place.","TWN":"或許從一開始，她就只打算利用我們的情報。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATCHER_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"필요한 걸 얻으려면 누구든 서로를 이용하는 법이지.","JPN":"欲しいものを手に入れるためには、お互い利用し合うものだ。","ENG":"People always use each other to get what they need.","TWN":"為了得到自己想要的東西，大家都會互相利用。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATCHER_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"우리도 마찬가지로 그녀를 이용하고 있으니까.","JPN":"我々も同じく、彼女を利用している。","ENG":"And we're using her too.","TWN":"我們也同樣在利用她。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATCHER_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WATCHER_NPC_NULL_14","text":{"KOREA":"규율을 위반한 자를 방치하는 건 바람직하지 않습니다.","JPN":"規律に背いた者を放置するのは、あまり望ましくありません。","ENG":"Allowing rule-breakers to walk free sets a bad example.","TWN":"但放任違反紀律的人不管，似乎不妥。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATCHER_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"WATCHER_NPC_NULL_14","text":{"KOREA":"충성하는 형제들에게 좋은 본보기를 보여야겠죠.","JPN":"忠誠を尽くす兄弟たちに手本を見せませんと。","ENG":"We must show the loyal Brothers what happens in such a case.","TWN":"應該要給忠心的弟兄們一個好的榜樣。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATCHER_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"쉽진 않을 거야.","JPN":"簡単ではないと思うが。","ENG":"It won't be easy.","TWN":"不容易喔。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATCHER_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"하지만 꼭 하고 싶다면… 본보기를 겸해서, 타깃도 함께 처리해주면 좋겠네.","JPN":"ただ、どうしてもそうしたいのなら……手本を兼ねて、ターゲットもまとめて排除したほうがいいだろう。","ENG":"But if you insist… Let's make an example of her, and eliminate the target while you're at it.","TWN":"但若你執意如此…那樹立榜樣的同事，也順便把目標一起處理掉吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATCHER_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"WATCHER_NPC_NULL_14","text":{"KOREA":"말씀대로 처리하겠습니다.","JPN":"そういたします。","ENG":"As you command.","TWN":"遵命。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATCHER_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"WATCHER_NPC_NULL_14","text":{"KOREA":"…펠릭스님.","JPN":"……フェリックス様。","ENG":"…Miss Felix.","TWN":"…緋莉克絲。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATCHER_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"}]`);export{e as default};